-- AUTO-GENERATO da data/cards.seed.json — rigenera con: node scripts/gen-seed.mjs
-- Re-seed: testi WOOH + colonna penalty (WOOH da bere se salti la carta)

alter table public.cards add column if not exists penalty int not null default 2;

on conflict (slug) do update set
  name = excluded.name,
  description = excluded.description,
  intensity = excluded.intensity,
  is_premium = excluded.is_premium,
  min_players = excluded.min_players,
  sort_order = excluded.sort_order;

delete from public.cards;
