insert into public.cards (deck_id, type, text, param, is_persistent, needs_target, min_players, penalty, sort_order) values
  ((select id from public.decks where slug='start'), 'wooh', $j${"it":"Benvenuti a The WOOH Game! Se hai capito cos'è il WOOH, distribuisci 3 WOOH e tutti insieme urlate WOOH con il tono più assurdo che potete.","en":"Welcome to The WOOH Game! If you get what WOOH means, hand out 3 WOOH and everyone shouts WOOH in the most absurd tone possible."}$j$::jsonb, null, false, 0, 3, 1, 1),
  ((select id from public.decks where slug='start'), 'io_non_ho_mai', $j${"it":"Io non ho mai mandato un messaggio alla persona sbagliata. Chi l'ha fatto, beve.","en":"Never have I ever texted the wrong person. Whoever has, drinks."}$j$::jsonb, null, false, 0, 3, 1, 2),
  ((select id from public.decks where slug='start'), 'io_non_ho_mai', $j${"it":"Io non ho mai finto di aver capito una battuta che non avevo capito. Chi l'ha fatto, beve.","en":"Never have I ever pretended to get a joke I didn't get. Whoever has, drinks."}$j$::jsonb, null, false, 0, 3, 1, 3),
  ((select id from public.decks where slug='start'), 'io_non_ho_mai', $j${"it":"Io non ho mai cantato a squarciagola in macchina da solo. Chi l'ha fatto, beve.","en":"Never have I ever belted out a song alone in the car. Whoever has, drinks."}$j$::jsonb, null, false, 0, 3, 1, 4),
  ((select id from public.decks where slug='start'), 'tre_cose', $j${"it":"Di' 3 cose che hai nel telefono in questo momento e di cui un po' ti vergogni. Se non ne dici 3, bevi.","en":"Name 3 things in your phone right now that you're a little ashamed of. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 3, 1, 5),
  ((select id from public.decks where slug='start'), 'tre_cose', $j${"it":"Le prime 3 cose che faresti se vincessi 10 milioni domani. Se non ne dici 3, bevi.","en":"The first 3 things you'd do if you won 10 million tomorrow. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 3, 1, 6),
  ((select id from public.decks where slug='start'), 'sinonimi', $j${"it":"A turno, dite un sinonimo di \"essere ubriaco\". Il primo che non sa cosa dire, beve.","en":"Take turns saying a synonym for \"being drunk\". First one stuck, drinks."}$j$::jsonb, $j${"tema":{"it":"essere ubriaco","en":"being drunk"}}$j$::jsonb, false, 0, 3, 1, 7),
  ((select id from public.decks where slug='start'), 'sinonimi', $j${"it":"A turno, dite un sinonimo di \"soldi\". Il primo che non sa cosa dire, beve.","en":"Take turns saying a synonym for \"money\". First one stuck, drinks."}$j$::jsonb, $j${"tema":{"it":"soldi","en":"money"}}$j$::jsonb, false, 0, 3, 1, 8),
  ((select id from public.decks where slug='start'), 'azione', $j${"it":"Fai un complimento sincero a {player}. Se ti viene da ridere, bevi.","en":"Give {player} a sincere compliment. If you laugh, you drink."}$j$::jsonb, null, false, 1, 3, 1, 9),
  ((select id from public.decks where slug='start'), 'azione', $j${"it":"Imita {player} finché gli altri non indovinano chi è. Se non ci riesci, bevi.","en":"Imitate {player} until the others guess who it is. Fail and you drink."}$j$::jsonb, null, false, 1, 3, 1, 10),
  ((select id from public.decks where slug='start'), 'regola', $j${"it":"REGOLA: fino alla prossima regola, nessuno può chiamare gli altri per nome. Chi sbaglia, beve.","en":"RULE: until the next rule, no one may call others by name. Slip up, drink."}$j$::jsonb, null, true, 0, 3, 1, 11),
  ((select id from public.decks where slug='start'), 'regola', $j${"it":"REGOLA: fino alla prossima regola, ogni volta che qualcuno dice \"sì\" beve un WOOH.","en":"RULE: until the next rule, every time someone says \"yes\" they take a WOOH."}$j$::jsonb, null, true, 0, 3, 1, 12),
  ((select id from public.decks where slug='mood'), 'wooh', $j${"it":"Momento WOOH: l'ultimo che alza le mani e urla WOOH distribuisce 2 WOOH.","en":"WOOH moment: the last to raise their hands and shout WOOH hands out 2 WOOH."}$j$::jsonb, null, false, 0, 3, 2, 1),
  ((select id from public.decks where slug='mood'), 'io_non_ho_mai', $j${"it":"Io non ho mai mentito sulla mia età. Chi l'ha fatto, beve.","en":"Never have I ever lied about my age. Whoever has, drinks."}$j$::jsonb, null, false, 0, 3, 2, 2),
