  ((select id from public.decks where slug='mood'), 'tre_cose', $j${"it":"Le prime 3 cose che faresti se per un giorno cambiassi genere. Se non ne dici 3, bevi.","en":"The first 3 things you'd do if you swapped gender for a day. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 3, 2, 4),
  ((select id from public.decks where slug='mood'), 'tre_cose', $j${"it":"Di' 3 persone in questa stanza con cui andresti su un'isola deserta. Se non ne dici 3, bevi.","en":"Name 3 people in this room you'd take to a desert island. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 3, 2, 5),
