  ((select id from public.decks where slug='mood'), 'azione', $j${"it":"Lascia che {player} scriva un messaggio dal tuo telefono all'ultima persona con cui hai chattato. Se rifiuti, bevi 3 WOOH.","en":"Let {player} send a message from your phone to the last person you chatted with. Refuse and drink 3."}$j$::jsonb, null, false, 1, 3, 2, 8),
