  ((select id from public.decks where slug='mood'), 'regola', $j${"it":"REGOLA: nominate un \"capitano\". Quando lui beve, bevono tutti. Vale fino alla prossima regola.","en":"RULE: pick a \"captain\". When they drink, everyone drinks. Until the next rule."}$j$::jsonb, null, true, 0, 3, 2, 10),
