  ((select id from public.decks where slug='hot'), 'io_non_ho_mai', $j${"it":"Io non ho mai avuto una cotta per un amico o un'amica presente stasera. Chi l'ha fatto, beve.","en":"Never have I ever had a crush on a friend who's here tonight. Whoever has, drinks."}$j$::jsonb, null, false, 0, 3, 3, 3),
  ((select id from public.decks where slug='hot'), 'tre_cose', $j${"it":"Di' 3 cose che trovi irresistibili in una persona. Se non ne dici 3, bevi.","en":"Name 3 things you find irresistible in a person. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 3, 3, 4),
  ((select id from public.decks where slug='hot'), 'azione', $j${"it":"Sussurra all'orecchio di {player} la cosa più audace che ti viene in mente. Se non lo fai, bevi 3 WOOH.","en":"Whisper the boldest thing you can think of in {player}'s ear. Don't, and drink 3."}$j$::jsonb, null, false, 1, 3, 3, 5),
