  ((select id from public.decks where slug='hot'), 'azione', $j${"it":"Mima con {player} la posa di coppia più teatrale e hot che riesci a inventare. Più è esagerata, meglio è.","en":"Strike the most theatrical, over-the-top couple pose with {player} you can invent. The bigger, the better."}$j$::jsonb, null, false, 1, 3, 3, 7),
  ((select id from public.decks where slug='hot'), 'manichino', $j${"it":"{player}, prendi {player2}: è il tuo manichino. Puoi mettergli le braccia in pose buffe finché non esce un'altra regola.","en":"{player}, take {player2}: they're your mannequin. Pose their arms however you like until the next rule."}$j$::jsonb, null, true, 2, 4, 3, 8),
  ((select id from public.decks where slug='hot'), 'regola', $j${"it":"REGOLA: fino alla prossima regola, ogni volta che qualcuno ride deve fare un complimento piccante a chi ha di fianco.","en":"RULE: until the next rule, anyone who laughs must give a spicy compliment to the person next to them."}$j$::jsonb, null, true, 0, 3, 3, 9),
  ((select id from public.decks where slug='coppia'), 'wooh', $j${"it":"Momento WOOH di coppia: contate insieme 3, 2, 1 e urlate WOOH. Chi parte in ritardo, beve.","en":"Couple WOOH moment: count 3, 2, 1 together and shout WOOH. Whoever's late, drinks."}$j$::jsonb, null, false, 0, 2, 2, 1),
  ((select id from public.decks where slug='coppia'), 'io_non_ho_mai', $j${"it":"Io non ho mai pensato a te durante una canzone. Se è falso, bevi.","en":"Never have I ever thought of you during a song. If that's a lie, drink."}$j$::jsonb, null, false, 0, 2, 2, 2),
  ((select id from public.decks where slug='coppia'), 'tre_cose', $j${"it":"Di' 3 cose che ti piacciono dell'altra persona e che non le hai mai detto. Se non ne dici 3, bevi.","en":"Name 3 things you like about the other person you've never told them. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 2, 2, 3),
  ((select id from public.decks where slug='coppia'), 'azione', $j${"it":"Guarda {player} negli occhi per 30 secondi senza parlare. Chi distoglie lo sguardo per primo, beve.","en":"Stare into {player}'s eyes for 30 seconds in silence. First to look away, drinks."}$j$::jsonb, null, false, 1, 2, 2, 4),
  ((select id from public.decks where slug='coppia'), 'azione', $j${"it":"Dai un bacio sulla guancia o sul collo a {player}, scegli tu dove. Se non lo fai, bevi 2 WOOH.","en":"Give {player} a kiss on the cheek or neck, your choice. Don't, and drink 2."}$j$::jsonb, null, false, 1, 2, 2, 5),
  ((select id from public.decks where slug='coppia'), 'regola', $j${"it":"REGOLA: fino alla prossima regola dovete restare con le mani intrecciate. Chi si stacca, beve.","en":"RULE: until the next rule you must keep your hands intertwined. Let go, and drink."}$j$::jsonb, null, true, 0, 2, 2, 6),
  ((select id from public.decks where slug='ambiente'), 'wooh', $j${"it":"WOOH ambientale: il primo che trova qualcosa di giallo nella stanza e lo alza urlando WOOH distribuisce 2 WOOH.","en":"Surroundings WOOH: first to find something yellow in the room and raise it shouting WOOH hands out 2 WOOH."}$j$::jsonb, null, false, 0, 3, 1, 1),
