  ((select id from public.decks where slug='ambiente'), 'azione', $j${"it":"Chi ha lo schermo del telefono più rovinato beve. Mostratelo tutti.","en":"Whoever has the most cracked phone screen drinks. Everyone show it."}$j$::jsonb, null, false, 0, 3, 1, 4),
  ((select id from public.decks where slug='ambiente'), 'regola', $j${"it":"REGOLA: fino alla prossima regola, chi appoggia il bicchiere senza usare un sottobicchiere (o un oggetto al posto suo) beve.","en":"RULE: until the next rule, anyone who sets their glass down without a coaster (or a stand-in) drinks."}$j$::jsonb, null, true, 0, 3, 1, 5),
